export default function Question() {
  const questions = [
    {
      img: "/assets/question1.png",
      text: "Which segments are the most risk-prone?",
    },
    {
      img: "/assets/question2.png",
      text: "Where are the risk hotspots across the country?",
    },
    {
      img: "/assets/question3.png",
      text: "what correlations exist between risk rates and other factors?",
    },
  ];

  return (
    <div style={{
      background: `radial-gradient(ellipse 70% 80% at 100% 50%, rgba(28,67,185,0.55) 0%, transparent 65%), #0d0d0d`,
      minHeight: "100vh",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      padding: "100px 64px",
    }}>
      {/* Title */}
      <h2 style={{
        fontFamily: "'Inter','Helvetica Neue',sans-serif",
        fontSize: "clamp(44px,6.5vw,100px)",
        fontWeight: 800, color: "white",
        margin: "0 0 56px", textAlign: "center", lineHeight: 1.08,
        maxWidth: 1100,
      }}>
        This section<br />
        <span style={{ fontWeight: 900 }}>answers questions like</span>
      </h2>

      {/* Cards */}
      <div style={{
        display: "grid", gridTemplateColumns: "repeat(3,1fr)",
        gap: 20, width: "100%", maxWidth: 1100,
      }}>
        {questions.map((q, i) => (
          <div key={i} style={{
            background: "rgba(255,255,255,0.06)",
            border: "1px solid rgba(255,255,255,0.12)",
            borderRadius: 16, padding: "28px 28px",
            display: "flex", alignItems: "center", gap: 20,
          }}>
            <div style={{
              width: 72, height: 72, flexShrink: 0,
              background: "rgba(255,255,255,0.08)",
              borderRadius: 12,
              display: "flex", alignItems: "center", justifyContent: "center",
              overflow: "hidden",
            }}>
              <img src={q.img} alt="" style={{ width: 48, height: 48, objectFit: "contain" }} />
            </div>
            <p style={{
              color: "white", fontSize: "clamp(14px,1.1vw,18px)",
              fontWeight: 500, margin: 0, lineHeight: 1.5,
              fontFamily: "'Inter',sans-serif",
            }}>{q.text}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
